import { test, expect } from '@playwright/test'

test.describe('Monthly Reflection Flow', () => {
  test.beforeEach(async ({ page }) => {
    // Sign in as test student
    await page.goto('/sign-in')
    await page.fill('[name=email]', 'test-student@compass.test')
    await page.fill('[name=password]', process.env.TEST_USER_PASSWORD!)
    await page.click('[type=submit]')
    await page.waitForURL('/')
  })

  test('completes full 5-step reflection', async ({ page }) => {
    // Start reflection
    await page.click('text=Start Monthly Reflection')
    await page.waitForURL(/\/reflect\//)

    // Step 1: Pulse Check
    await expect(page.locator('h2')).toContainText('How are you showing up')
    await page.click('[data-pulse="4"]') // "Good"
    await page.click('text=Continue')

    // Step 2: Activity Logger
    await expect(page.locator('h2')).toContainText('What have you been up to')
    await page.click('text=Add Activity')
    await page.fill('[name=activityName]', 'Robotics Club')
    await page.selectOption('[name=category]', 'EXTRACURRICULAR')
    await page.click('[data-excitement="5"]')
    await page.click('text=Add')
    await page.click('text=Continue to Reflection')

    // Step 3: Reflection prompts (AI-generated)
    await expect(page.locator('h2')).toContainText('Reflect')
    await page.waitForSelector('[data-testid=prompt-text]')
    const prompt = await page.locator('[data-testid=prompt-text]').first().textContent()
    expect(prompt).toBeTruthy()
    await page.fill('textarea', 'I find that engineering problems engage me because...')
    await page.click('text=Save & Continue')

    // Step 4: Map Moment
    await expect(page.locator('h2')).toContainText('Map Moment')
    await page.click('text=Continue')

    // Step 5: Privacy Review
    await expect(page.locator('h2')).toContainText('Privacy')
    await page.click('text=Submit Reflection')

    // Completion
    await page.waitForURL(/\/complete/)
    await expect(page.locator('h2')).toContainText('Complete')
  })
})
