'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { motion, AnimatePresence } from 'framer-motion'
import { useUser } from '@clerk/nextjs'

const ONBOARDING_STEPS = [
  'welcome',
  'grade',
  'school',
  'interests-seed',
  'notification-setup',
  'privacy-intro',
] as const

export default function OnboardingPage() {
  const [step, setStep] = useState(0)
  const [data, setData] = useState<Record<string, any>>({})
  const router = useRouter()
  const { user } = useUser()

  const handleStepData = async (stepData: any) => {
    const merged = { ...data, ...stepData }
    setData(merged)

    if (step === ONBOARDING_STEPS.length - 1) {
      // Final step — save all onboarding data
      await fetch('/api/students/onboarding', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(merged),
      })
      router.push('/')
    } else {
      setStep(prev => prev + 1)
    }
  }

  return (
    <div className="min-h-screen bg-bg-primary flex items-center justify-center p-6">
      <div className="w-full max-w-md">
        {/* Progress dots */}
        <div className="flex justify-center gap-2 mb-8">
          {ONBOARDING_STEPS.map((_, i) => (
            <div
              key={i}
              className={`w-2 h-2 rounded-full transition-all duration-300 ${
                i <= step ? 'bg-accent-primary w-4' : 'bg-slate-300'
              }`}
            />
          ))}
        </div>

        <AnimatePresence mode="wait">
          <motion.div
            key={step}
            initial={{ opacity: 0, x: 30 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -30 }}
            transition={{ duration: 0.25 }}
          >
            <OnboardingStep
              stepId={ONBOARDING_STEPS[step]}
              onComplete={handleStepData}
              firstName={user?.firstName}
            />
          </motion.div>
        </AnimatePresence>
      </div>
    </div>
  )
}
