import { Redis } from '@upstash/redis'

export const redis = new Redis({
  url: process.env.UPSTASH_REDIS_REST_URL!,
  token: process.env.UPSTASH_REDIS_REST_TOKEN!,
})

// Cache keys
export const CACHE_KEYS = {
  studentProfile: (id: string) => `student:${id}:profile`,
  counselorStudents: (counselorId: string) => `counselor:${counselorId}:students`,
  mapNodes: 'map:nodes:all',
  personalizedMap: (studentId: string) => `map:${studentId}:personalized`,
  signalProfile: (studentId: string) => `signals:${studentId}`,
  meetingPrep: (studentId: string, counselorId: string) =>
    `counselor:${counselorId}:prep:${studentId}`,
} as const

// TTL values in seconds
export const TTL = {
  studentProfile: 60 * 5,         // 5 minutes
  counselorStudents: 60 * 2,      // 2 minutes
  mapNodes: 60 * 60 * 24,         // 24 hours (map data rarely changes)
  personalizedMap: 60 * 60,       // 1 hour
  signalProfile: 60 * 10,         // 10 minutes
  meetingPrep: 60 * 60 * 24,      // 24 hours
} as const

export async function withCache<T>(
  key: string,
  ttl: number,
  fetcher: () => Promise<T>
): Promise<T> {
  const cached = await redis.get<T>(key)
  if (cached !== null) return cached

  const fresh = await fetcher()
  await redis.setex(key, ttl, JSON.stringify(fresh))
  return fresh
}

export async function invalidateCache(...keys: string[]) {
  if (keys.length === 0) return
  await redis.del(...keys)
}
```

### 14.2 Applying Cache to Hot Paths

The personalized map query is cache-worthy because it involves a vector similarity search. Apply caching in the API route:

```typescript
// In apps/web/app/api/map/personalized/route.ts — updated version

import { withCache, CACHE_KEYS, TTL, invalidateCache } from '@/lib/cache'

export async function GET() {
  const student = await requireStudent()

  const data = await withCache(
    CACHE_KEYS.personalizedMap(student.id),
    TTL.personalizedMap,
    async () => {
      // ... full vector query (expensive)
    }
  )

  return apiSuccess(data)
}
```

Cache invalidation triggers:
- Signal profile updated → invalidate `personalizedMap`, `signalProfile`
- Student completes session → invalidate `studentProfile`, `counselorStudents`
- New activities added → no cache invalidation needed (activities are real-time)

